theme.custom_css_code:
/* ELEMENT 1 — BRAND TABLE */
.clover-brand-card{
  --cb-bg:#163723;
  --cb-bg-soft:#1d452c;
  --cb-line:rgba(255,255,255,.12);
  --cb-text:#f4f7f2;
  --cb-muted:#b8c8bb;
  --cb-accent:#7ee2a0;
  width:100%;
  max-width:920px;
  margin:0;
  border:1px solid var(--cb-line);
  border-radius:20px;
  background:linear-gradient(180deg, rgba(22,55,35,.96) 0%, rgba(15,42,24,.92) 100%);
  overflow:hidden;
  box-shadow:0 18px 40px rgba(0,0,0,.22);
  font-family:Arial,sans-serif;
}
.clover-brand-table-wrap{
  width:100%;
  overflow-x:auto;
}
.clover-brand-table{
  width:100%;
  min-width:640px;
  border-collapse:collapse;
  color:var(--cb-text);
}
.clover-brand-table tr:not(:last-child){
  border-bottom:1px solid var(--cb-line);
}
.clover-brand-table td{
  padding:16px 18px;
  vertical-align:top;
  font-size:15px;
  line-height:1.5;
}
.clover-brand-table td:first-child{
  width:34%;
  color:var(--cb-muted);
  background:rgba(255,255,255,.03);
  font-weight:700;
  letter-spacing:.2px;
}
.clover-brand-pill{
  display:inline-block;
  padding:6px 10px;
  border-radius:999px;
  background:rgba(126,226,160,.12);
  border:1px solid rgba(126,226,160,.25);
  color:var(--cb-accent);
  font-size:13px;
  font-weight:700;
  white-space:nowrap;
}
@media (max-width:640px){
  .clover-brand-table td{
    padding:14px 14px;
    font-size:14px;
  }
}
/* ELEMENT 2 — GAMES TILES */
.clover-games-grid{
  --cg-bg:#163723;
  --cg-line:rgba(255,255,255,.11);
  --cg-text:#f5f8f3;
  --cg-muted:#bdd0c1;
  --cg-accent:#89ecaa;
  --cg-accent-soft:rgba(137,236,170,.14);
  display:grid;
  grid-template-columns:repeat(4,minmax(0,1fr));
  gap:16px;
  width:100%;
  max-width:920px;
  margin:0;
  font-family:Arial,sans-serif;
}
.clover-game-tile{
  position:relative;
  min-height:180px;
  border-radius:22px;
  padding:18px;
  background:linear-gradient(180deg, rgba(22,55,35,.96) 0%, rgba(15,42,24,.92) 100%);
  border:1px solid var(--cg-line);
  overflow:hidden;
  box-shadow:0 16px 36px rgba(0,0,0,.22);
}
.clover-game-tile:before{
  content:"";
  position:absolute;
  inset:auto -24px -28px auto;
  width:96px;
  height:96px;
  border-radius:50%;
  background:radial-gradient(circle, rgba(137,236,170,.2) 0%, rgba(137,236,170,0) 70%);
}
.clover-game-icon{
  width:52px;
  height:52px;
  border-radius:16px;
  display:flex;
  align-items:center;
  justify-content:center;
  background:var(--cg-accent-soft);
  border:1px solid rgba(137,236,170,.22);
  font-size:26px;
  margin-bottom:16px;
}
.clover-game-title{
  color:var(--cg-text);
  font-size:18px;
  line-height:1.25;
  font-weight:700;
  margin:0 0 8px;
}
.clover-game-copy{
  color:var(--cg-muted);
  font-size:14px;
  line-height:1.55;
  margin:0 0 14px;
}
.clover-game-tag{
  display:inline-block;
  padding:6px 10px;
  border-radius:999px;
  color:var(--cg-accent);
  background:rgba(137,236,170,.1);
  border:1px solid rgba(137,236,170,.18);
  font-size:12px;
  font-weight:700;
  letter-spacing:.2px;
}
@media (max-width:900px){
  .clover-games-grid{
    grid-template-columns:repeat(2,minmax(0,1fr));
  }
}
@media (max-width:560px){
  .clover-games-grid{
    grid-template-columns:1fr;
  }
  .clover-game-tile{
    min-height:auto;
  }
}
/* ELEMENT 3 — BAR CHART */
.clover-chart-card{
  --cc-bg:#163723;
  --cc-line:rgba(255,255,255,.11);
  --cc-track:rgba(255,255,255,.07);
  --cc-fill:linear-gradient(90deg, #72d893 0%, #a6f0bf 100%);
  --cc-text:#f5f8f3;
  --cc-muted:#bdd0c1;
  width:100%;
  max-width:920px;
  margin:0;
  padding:22px 18px;
  border-radius:22px;
  background:linear-gradient(180deg, rgba(22,55,35,.96) 0%, rgba(15,42,24,.92) 100%);
  border:1px solid var(--cc-line);
  box-shadow:0 18px 40px rgba(0,0,0,.22);
  font-family:Arial,sans-serif;
}
.clover-chart-row{
  display:grid;
  grid-template-columns:180px 1fr 54px;
  gap:14px;
  align-items:center;
}
.clover-chart-row:not(:last-child){
  margin-bottom:14px;
}
.clover-chart-label{
  color:var(--cc-text);
  font-size:14px;
  font-weight:700;
  line-height:1.3;
}
.clover-chart-track{
  position:relative;
  height:14px;
  border-radius:999px;
  background:var(--cc-track);
  overflow:hidden;
}
.clover-chart-fill{
  position:absolute;
  inset:0 auto 0 0;
  width:var(--w);
  border-radius:999px;
  background:var(--cc-fill);
  box-shadow:0 0 18px rgba(166,240,191,.25);
}
.clover-chart-value{
  color:var(--cc-muted);
  font-size:13px;
  font-weight:700;
  text-align:right;
}
@media (max-width:640px){
  .clover-chart-row{
    grid-template-columns:1fr;
    gap:8px;
  }
  .clover-chart-value{
    text-align:left;
  }
}
